      maxTokens: 1024,
      temperature: 0.3,
      module: 'admin',
      feature: 'nl-query',
    });

    res.json({ question, answer, data: { summary, models, modules, budget } });
  } catch (err) {
    res.status(500).json({ error: 'Query failed', message: err.message });
  }
});

