                  <div
                    key={i}
                    className={cn(
                      'flex-1 rounded-t-sm transition-all',
                      day.tokensUsed >= day.budget ? 'bg-red-400' : 'bg-primary/60',
                    )}
                    style={{ height: `${Math.min(100, h)}%` }}
                    title={`${day.date}: ${day.tokensUsed.toLocaleString()} tokens`}
                  />
                )
              })}
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  )
}

