              </Card>
            </div>
          </>
        )}

        {/* ─── AI PROVIDERS TAB ─── */}
        {activeTab === 'ai' && (
          <>
            {/* Modality Status Cards */}
            <div>
              <div className="flex items-center gap-2 mb-4">
                <Cpu className="h-5 w-5 text-muted-foreground" />
